proof fn phi_1_interp_of_entry_implies_interp_external_body(d: Directory, j: nat, va: nat, pte: PTE)
    requires
        d.inv(),
        j < d.entries.len(),
        d.interp_of_entry(j).contains_pair(va, pte),
    ensures
        d.interp().contains_pair(va, pte),
{
    d.lemma_interp_of_entry_contains_mapping_implies_interp_contains_mapping(j);
}

proof fn phi_2_interp_of_entry_key_implies_interp_key_external_body(d: Directory, j: nat, va: nat)
    requires
        d.inv(),
        j < d.entries.len(),
        d.interp_of_entry(j).contains_key(va),
    ensures
        d.interp().contains_key(va),
{
    d.lemma_interp_of_entry_contains_mapping_implies_interp_contains_mapping(j);
}
